import{_ as r,c as d,o as l,a5 as t,j as a}from"./chunks/framework.Dtwt352Q.js";const b=JSON.parse('{"title":"v1.1.12：组织订阅支持","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.12.md","filePath":"changelog/v1.1.12.md","lastUpdated":1772014034000}'),n={name:"changelog/v1.1.12.md"};function o(i,e,h,s,c,p){return l(),d("div",null,[...e[0]||(e[0]=[t('<h1 id="v1-1-12-组织订阅支持" tabindex="-1">v1.1.12：组织订阅支持 <a class="header-anchor" href="#v1-1-12-组织订阅支持" aria-label="Permalink to “v1.1.12：组织订阅支持”">​</a></h1><p><strong>发布日期</strong>：2026年1月10日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新让 <strong>OpenAI 组织订阅用户</strong> 可以正常使用 OpenCode，解决了之前组织账户无法正确识别的问题。</p><hr><h2 id="问题修复-openai-组织订阅支持" tabindex="-1">问题修复：OpenAI 组织订阅支持 <a class="header-anchor" href="#问题修复-openai-组织订阅支持" aria-label="Permalink to “问题修复：OpenAI 组织订阅支持”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>如果你的 OpenAI 账户属于某个<strong>组织（Organization）</strong>，比如公司购买的 API 订阅，之前可能会遇到：</p><ul><li>API 调用失败</li><li>账单计入错误的账户</li><li>无法使用组织的配额</li></ul><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>OpenCode 现在会自动发送 <code>ChatGPT-Account-Id</code> header，确保：</p><ul><li>✅ API 调用正确关联到你的组织账户</li><li>✅ 费用计入组织账单</li><li>✅ 使用组织的 API 配额</li></ul><h3 id="谁需要关注" tabindex="-1">谁需要关注？ <a class="header-anchor" href="#谁需要关注" aria-label="Permalink to “谁需要关注？”">​</a></h3><table tabindex="0"><thead><tr><th>情况</th><th>影响</th></tr></thead><tbody><tr><td>个人 OpenAI 账户</td><td>无影响，正常使用</td></tr><tr><td>公司/组织 OpenAI 账户</td><td>✅ 修复了之前的问题</td></tr><tr><td>使用其他模型（DeepSeek、Claude 等）</td><td>无影响</td></tr></tbody></table><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用公司/组织的 OpenAI 账户</td><td>✅ 必须升级</td></tr><tr><td>个人 OpenAI 账户</td><td>可以升级，无副作用</td></tr><tr><td>不用 OpenAI</td><td>可以等下次一起升级</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',19),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>为组织订阅添加 <code>ChatGPT-Account-Id</code> HTTP header（@fdematos）</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><ul><li>@vtemian：文档添加 micode 和 octto 插件</li><li>@fdematos：修复组织订阅的 Account-Id header</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const m=r(n,[["render",o]]);export{b as __pageData,m as default};
